import java.util.TreeMap;

class RangeModule {

    private TreeMap<Integer, Integer> intervals;

    public RangeModule() {
        intervals = new TreeMap<>();
    }

    public void addRange(int left, int right) {
        intervals.entrySet().removeIf(entry -> entry.getValue() <= left || entry.getKey() >= right);
        if (intervals.isEmpty() || intervals.lastEntry().getKey() < left) {
            intervals.put(left, right);
        } else {
            int start = intervals.floorKey(left);
            intervals.put(start, Math.max(intervals.get(start), right));
        }
    }

    public boolean queryRange(int left, int right) {
        Integer floor = intervals.floorKey(left);
        return floor != null && intervals.get(floor) >= right;
    }

    public void removeRange(int left, int right) {
        Integer floor = intervals.floorKey(left);
        if (floor != null && intervals.get(floor) > left) {
            intervals.put(floor, left);
        }
        while (!intervals.isEmpty() && intervals.firstKey() < right) {
            if (intervals.firstKey() < right && intervals.get(intervals.firstKey()) <= right) {
                intervals.remove(intervals.firstKey());
            } else {
                intervals.put(intervals.firstKey(), right);
                break;
            }
        }
    }
}
